#include "Assets/ParticleAsset.h"
#include <algorithm>
#include <filesystem>
#include <fstream>
namespace{nlohmann::json Vec(const Vec3& v){return{v.x,v.y,v.z};}Vec3 Read(const nlohmann::json& j,const Vec3& f){return j.is_array()&&j.size()==3?Vec3(j[0].get<float>(),j[1].get<float>(),j[2].get<float>()):f;}}
bool SaveParticleAssetToFile(const ParticleAsset& asset,const std::string& path){try{const auto&s=asset.GetSettings();nlohmann::json j={{"version",1},{"maxParticles",s.maxParticles},{"rate",s.rate},{"burst",s.burst},{"lifetime",s.lifetime},{"startSpeed",s.startSpeed},{"startSize",s.startSize},{"endSize",s.endSize},{"startColor",Vec(s.startColor)},{"endColor",Vec(s.endColor)},{"startAlpha",s.startAlpha},{"endAlpha",s.endAlpha},{"loop",s.loop},{"playOnStart",s.playOnStart}};std::filesystem::create_directories(std::filesystem::path(path).parent_path());std::ofstream out(path,std::ios::binary|std::ios::trunc);out<<j.dump(2);return static_cast<bool>(out);}catch(...){return false;}}
std::shared_ptr<ParticleAsset> LoadParticleAssetFromFile(const std::string& path){try{std::ifstream in(path,std::ios::binary);nlohmann::json j;in>>j;if(j.value("version",0)!=1)return{};auto asset=std::make_shared<ParticleAsset>(path);auto&s=asset->GetSettings();s.maxParticles=std::max(1u,j.value("maxParticles",256u));s.rate=std::max(0.0f,j.value("rate",20.0f));s.burst=j.value("burst",0u);s.lifetime=std::max(0.01f,j.value("lifetime",1.5f));s.startSpeed=j.value("startSpeed",1.0f);s.startSize=std::max(0.0f,j.value("startSize",0.2f));s.endSize=std::max(0.0f,j.value("endSize",0.0f));s.startColor=Read(j.value("startColor",nlohmann::json::array()),Vec3::One());s.endColor=Read(j.value("endColor",nlohmann::json::array()),Vec3::One());s.startAlpha=std::clamp(j.value("startAlpha",1.0f),0.0f,1.0f);s.endAlpha=std::clamp(j.value("endAlpha",0.0f),0.0f,1.0f);s.loop=j.value("loop",true);s.playOnStart=j.value("playOnStart",true);asset->MarkReady();return asset;}catch(...){return{};}}
